<script>
export default {
  name: "getUserInfo", // 这个名字推荐：大写字母开头驼峰法命名。
  props: {},
  components: {},
  directives: {},
  mixins: [],
  data() {
    return {
      deviceReady: false,
      devicePlatform: "",
    };
  },
  computed: {},
  created() {},
  mounted() {
    document.addEventListener("deviceready", this.onDeviceReady, false);
    //后退 按钮监听
    document.addEventListener("backbutton", this.hback);
    // 添加事件监听

    document.addEventListener("load", function () {
      console.log("横竖屏监听");
      this.orientationChange();

      window.onorientationchange = this.orientationChange;
    });
  },
  activated() {},
  deactivated() {},
  watch: {},
  methods: {
    onDeviceReady() {
      //alert("onDeviceReady()--->start()");
      deviceReady = 1;
      this.devicePlatform = device.platform;
      console.log("onDeviceReady()--->end()");

      if ("iOS" == this.devicePlatform) {
        mam.navigator.appmenu.setBackButton(null, null, "1");
      }
      //添加自定义 菜单
      this.AddMenu();
    },
    //后退 按钮监听
    hback() {
      if ("iOS" == devicePlatform) {
        mam.navigator.appmenu.setBackButton(null, null, "0");
      }
      document.removeEventListener("backbutton", this.hback);
      //以下三种，可根据当前页面需求，使用不同方法。
      //第一种：直接退出当前应用
      /**mam.navigator.appmenu.exitApp();**/
      //第二种：返回上一页
      /**history.go(-1);**/
      //第三种：自定义跳转页面
      //	window.location.href = "view/gateway.html";
      alert(
        '在这里定义回退事件，或者释放代码 window.location.href = "view/gateway.html";'
      );
    },

    //添加自定义 菜单
    AddMenu() {
      //有三种图标：”1”：默认国网；”2”：删除；”3”：设置备注
      mam.navigator.appmenu.addMenu(
        this.successCallback,
        null,
        "1",
        "自定义菜单1",
        "addMenuFun()"
      );
      mam.navigator.appmenu.addMenu(
        this.successCallback,
        null,
        "2",
        "自定义菜单2",
        "addMenuFun()"
      );
      mam.navigator.appmenu.addMenu(
        this.successCallback,
        null,
        "3",
        "自定义菜单3",
        "addMenuFun()"
      );
    },
    successCallback() {
      //alert("自定义菜单设置成功回调。");
    },
    addMenuFun() {
      alert("自定义菜单工能正常，此方法每个页面必须实现！");
    },

    // getUserInfo() {
    //   alert("2020-11  此插件废除，新 老 应用请使用 getToken。有问题咨询管理员");
    //   mam.navigator.loadconfig.getUserInfoNEW(getUserInfoCallback);
    // },
    getUserInfoCallback(obj) {
      if (obj.appType == 1) {
        alert(
          "统一框架(ISC)登录名: " +
            obj.nameCode +
            " 区域编号: " +
            obj.areaId +
            " 用户编号: " +
            obj.userId +
            " 登录用户姓名: " +
            obj.name +
            " 用户所属基准组织结构: " +
            obj.baseOrgId +
            " 用户所属组织机构名称: " +
            obj.baseOrgName
        );
      } else {
        alert(JSON.stringify(obj));
      }
      console.log("getUserInfo插件调用成功:" + JSON.stringify(obj));
    },
    /************************************************/
    // 判断屏幕是否旋转

    orientationChange() {
      switch (window.orientation) {
        case 0:
          console.log(
            "肖像模式 0,screen-width: " +
              screen.width +
              "; screen-height:" +
              screen.height
          );
          break;
        case -90:
          console.log(
            "左旋 -90,screen-width: " +
              screen.width +
              "; screen-height:" +
              screen.height
          );
          break;
        case 90:
          console.log(
            "右旋 90,screen-width: " +
              screen.width +
              "; screen-height:" +
              screen.height
          );
          break;
        case 180:
          console.log(
            "风景模式 180,screen-width: " +
              screen.width +
              "; screen-height:" +
              screen.height
          );
          break;
      }
    },

    accountLogin() {
      alert("accountLogin");
      mam.navigator.loadconfig.accountLogin(this.accountLoginCallback);
    },
    accountLoginCallback(obj) {
      alert(JSON.stringify(obj));
    },

    getMessage() {
      alert("getMessage");
      mam.navigator.loadconfig.messageInfo(this.getMsgCallback);
    },
    getMsgCallback(obj) {
      alert(JSON.stringify(obj));
    },

    loginAuth() {
      alert("loginAuth");
      mam.navigator.loadconfig.loginAuth(this.loginAuthCallback);
    },
    loginAuthCallback(obj) {
      alert(JSON.stringify(obj));
    },

    /**
	*	appcode				应用编码
	*	appCertificate		应用秘钥  即 umsecret 密码默认：【 seuUwLBxGfg 或 123456 】
		SGCCISCAppId		业务系统在isc注册的appid'   开发环境 默认使用， 生产环境找网省信通负责ISC的人申请
		SGCCISCService		业务系统在isc注册的service	开发环境 默认使用， 生产环境找网省信通负责ISC的人申请

		successCallback		成功回调
		errcallback			失败回调
		
	**/
    //	var SGCCISCAppId ='8a0621e152a090430152ab60c0fb0004';
    //	var SGCCISCService ='http://27.196.216.39:8082/jwt';

    getToken() {
      var appCode = document.getElementById("appCode").value;
      var umsecret = document.getElementById("umsecret").value;

      var SGCCISCAppId = document.getElementById("SGCCISCAppId").value;
      var SGCCISCService = document.getElementById("SGCCISCService").value;

      if (appCode == "" && umsecret == "") {
        appCode = "SYSCS";
        umsecret = "seuUwLBxGfg";
        console.log(
          "appCode  " +
            appCode +
            "  umsecret " +
            umsecret +
            "  SGCCISCAppId " +
            SGCCISCAppId +
            "  SGCCISCService " +
            SGCCISCService
        );

        mam.navigator.accessToken.getToken(
          appCode,
          umsecret,
          SGCCISCAppId,
          SGCCISCService,
          this.successCallback,
          this.errcallback
        );
      } else if (appCode != "" && umsecret != "") {
        console.log(
          "appCode  " +
            appCode +
            "  umsecret " +
            umsecret +
            "  SGCCISCAppId " +
            SGCCISCAppId +
            "  SGCCISCService " +
            SGCCISCService
        );
        mam.navigator.accessToken.getToken(
          appCode,
          umsecret,
          SGCCISCAppId,
          SGCCISCService,
          this.successCallback,
          this.errcallback
        );
      }
    },
    getTokenSYSCS() {
      var appCode = "SYSCS";
      var umsecret = "seuUwLBxGfg";
      alert("应用编码 = " + appCode + "  秘钥 = " + umsecret);
      console.log(
        "appCode  " +
          appCode +
          "  umsecret " +
          umsecret +
          "  SGCCISCAppId " +
          SGCCISCAppId +
          "  SGCCISCService " +
          SGCCISCService
      );
      mam.navigator.accessToken.getToken(
        appCode,
        umsecret,
        SGCCISCAppId,
        SGCCISCService,
        this.successCallback,
        this.errcallback
      );
    },
    successCallback(obj) {
      alert(JSON.stringify(obj));
      console.log(JSON.stringify(obj));
      //getUserInfo(obj);
    },
    errcallback(obj) {
      switch (obj.code.toString()) {
        case "-1":
          //参数异常
          mam.navigator.notification.alert("参数异常", function () {}, "提示");
          break;
        case "-2":
          //4、获取临时令牌失败
          mam.navigator.notification.alert(
            "获取临时令牌失败",
            function () {},
            "提示"
          );
          break;
        case "-3":
          //用户认证失效（建议重新登录i国网）
          mam.navigator.notification.alert(
            "用户认证失效,请退出重新登录i国网",
            function () {},
            "提示"
          );
          break;
      }
    },

    getUserInfo(obj) {
      //	alert('getUserInfo  '+obj.msg);
      let tokens = "";
      if (obj.code.toString() == "0") {
        if (obj.msg != "") {
          tokens = obj.msg;
        } else {
          mam.navigator.notification.alert(
            "令牌获取失败",
            function () {},
            "提示"
          );
          return;
        }
      }
      console.log("token信息：" + JSON.stringify(obj));
      var param1 = {
        serviceTK: tokens,
      };
      // 2020年11月18日 开发环境 正在调整。
      mam.navigator.ajax.postJSON(
        "SYSCS",
        { method: "getPlatformUser", param1: JSON.stringify(param1) },
        "TOKEN",
        function getusermess(obj) {
          console.log("用户信息为：" + JSON.stringify(obj));
          //处理自己的逻辑
        }
      );
    },
  },
};
</script>
